namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public required string Code { get; set; }
    public required string Title { get; set; }
    public required string Description { get; set; }
    public int Credits { get; set; }
    public required string Schedule { get; set; }
    public required string InstructorName { get; set; }
    public required string InstructorBio { get; set; }
    public required string DepartmentCode { get; set; }
    public bool IsFeatured { get; set; }
}

namespace UniversityCourseCatalog.Models;

public class Department
{
    public required string Code { get; set; }
    public required string Name { get; set; }
    public required string Description { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Full name is required.")]
    [StringLength(100)]
    public string FullName { get; set; } = "";

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Za-z0-9]{6,12}$", ErrorMessage = "Student ID must be 6–12 alphanumeric characters.")]
    public string StudentId { get; set; } = "";

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Code = "CS",   Name = "Computer Science",   Description = "Study of computation, algorithms, and information systems." },
        new() { Code = "MATH", Name = "Mathematics",         Description = "Pure and applied mathematics including statistics." },
        new() { Code = "ENG",  Name = "English",             Description = "Literature, writing, and language studies." },
        new() { Code = "PHYS", Name = "Physics",             Description = "Study of matter, energy, and the fundamental forces of nature." },
        new() { Code = "HIST", Name = "History",             Description = "Exploration of past events and civilizations." },
    ];

    private readonly List<Course> _courses =
    [
        new() { Id = 1,  Code = "CS 101",   Title = "Introduction to Programming",   Description = "Fundamentals of programming using Python. Covers variables, control flow, functions, and basic data structures.",                     Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM",  InstructorName = "Dr. Alice Chen",       InstructorBio = "Ph.D. in Computer Science from MIT. 15 years of teaching experience in introductory programming and software engineering.",            DepartmentCode = "CS",   IsFeatured = true },
        new() { Id = 2,  Code = "CS 201",   Title = "Data Structures & Algorithms",  Description = "In-depth study of arrays, linked lists, trees, graphs, sorting, and searching algorithms with complexity analysis.",                  Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM",    InstructorName = "Dr. Alice Chen",       InstructorBio = "Ph.D. in Computer Science from MIT. 15 years of teaching experience in introductory programming and software engineering.",            DepartmentCode = "CS",   IsFeatured = false },
        new() { Id = 3,  Code = "CS 310",   Title = "Database Systems",              Description = "Relational database design, SQL, normalization, transaction processing, and an introduction to NoSQL databases.",                       Credits = 3, Schedule = "Mon/Wed 1:00–2:15 PM",      InstructorName = "Prof. Brian Kowalski", InstructorBio = "Former database architect at Oracle. Specializes in distributed systems and data modeling.",                                            DepartmentCode = "CS",   IsFeatured = true },
        new() { Id = 4,  Code = "CS 450",   Title = "Machine Learning",              Description = "Supervised and unsupervised learning, neural networks, and practical applications using scikit-learn and TensorFlow.",                   Credits = 3, Schedule = "Tue/Thu 2:00–3:15 PM",      InstructorName = "Dr. Sarah Park",       InstructorBio = "AI researcher with publications in NeurIPS and ICML. Previously at Google DeepMind.",                                                  DepartmentCode = "CS",   IsFeatured = true },
        new() { Id = 5,  Code = "MATH 101", Title = "Calculus I",                    Description = "Limits, derivatives, and integrals of single-variable functions with applications to science and engineering.",                          Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. James Rivera",     InstructorBio = "Award-winning mathematics educator with 20 years of experience. Author of 'Calculus Made Clear'.",                                    DepartmentCode = "MATH", IsFeatured = true },
        new() { Id = 6,  Code = "MATH 201", Title = "Linear Algebra",                Description = "Vectors, matrices, linear transformations, eigenvalues, and applications to data science and engineering.",                              Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM",     InstructorName = "Dr. James Rivera",     InstructorBio = "Award-winning mathematics educator with 20 years of experience. Author of 'Calculus Made Clear'.",                                    DepartmentCode = "MATH", IsFeatured = false },
        new() { Id = 7,  Code = "MATH 310", Title = "Probability & Statistics",      Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.",                                      Credits = 3, Schedule = "Mon/Wed 2:30–3:45 PM",      InstructorName = "Prof. Diana Okafor",   InstructorBio = "Statistician with industry experience in biotech. Passionate about making statistics accessible.",                                     DepartmentCode = "MATH", IsFeatured = false },
        new() { Id = 8,  Code = "ENG 101",  Title = "College Composition",           Description = "Development of academic writing skills including argumentation, research methods, and critical analysis.",                                Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Prof. Michael Torres", InstructorBio = "Published author and writing workshop facilitator. MFA from the Iowa Writers' Workshop.",                                              DepartmentCode = "ENG",  IsFeatured = false },
        new() { Id = 9,  Code = "ENG 220",  Title = "American Literature",           Description = "Survey of American literary works from the colonial period to the present, exploring themes of identity, freedom, and society.",         Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM",      InstructorName = "Dr. Linda Yamamoto",   InstructorBio = "Scholar of 20th-century American fiction. Fulbright fellow and author of two critical monographs.",                                    DepartmentCode = "ENG",  IsFeatured = true },
        new() { Id = 10, Code = "PHYS 101", Title = "General Physics I",             Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions with hands-on experiments.",                                          Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM",  InstructorName = "Dr. Robert Nguyen",    InstructorBio = "Experimental physicist specializing in optics. Previously a researcher at Fermilab.",                                                  DepartmentCode = "PHYS", IsFeatured = false },
        new() { Id = 11, Code = "PHYS 250", Title = "Quantum Mechanics",             Description = "Introduction to quantum theory: wave functions, the Schrödinger equation, quantum states, and measurement.",                            Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", InstructorName = "Dr. Robert Nguyen",    InstructorBio = "Experimental physicist specializing in optics. Previously a researcher at Fermilab.",                                                  DepartmentCode = "PHYS", IsFeatured = false },
        new() { Id = 12, Code = "HIST 101", Title = "World History to 1500",         Description = "Survey of major civilizations, empires, and cultural exchanges from prehistory through the late medieval period.",                        Credits = 3, Schedule = "Mon/Wed 10:00–11:15 AM",    InstructorName = "Dr. Karen Hoffman",    InstructorBio = "Historian of the ancient Mediterranean world. Author of 'Empires in Context' and frequent lecturer at the Smithsonian.",              DepartmentCode = "HIST", IsFeatured = false },
        new() { Id = 13, Code = "HIST 205", Title = "Modern European History",       Description = "Political, social, and cultural developments in Europe from the Enlightenment through the 21st century.",                                Credits = 3, Schedule = "Tue/Thu 3:30–4:45 PM",      InstructorName = "Prof. Elena Vasquez",  InstructorBio = "Specialist in Cold War diplomacy and European integration. Former consultant to the EU Parliament history project.",                    DepartmentCode = "HIST", IsFeatured = true },
    ];

    public IReadOnlyList<Department> GetDepartments() => _departments;

    public Department? GetDepartment(string code) =>
        _departments.FirstOrDefault(d => d.Code.Equals(code, StringComparison.OrdinalIgnoreCase));

    public IReadOnlyList<Course> GetAllCourses() => _courses;

    public IReadOnlyList<Course> GetFeaturedCourses() =>
        _courses.Where(c => c.IsFeatured).ToList();

    public IReadOnlyList<Course> SearchCourses(string? searchTerm, string? departmentCode)
    {
        var query = _courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(departmentCode))
        {
            query = query.Where(c => c.DepartmentCode.Equals(departmentCode, StringComparison.OrdinalIgnoreCase));
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) =>
        _courses.FirstOrDefault(c => c.Id == id);
}

