@page "/courses"
@inject UniversityCourseCatalog.Services.CatalogService Catalog

<PageTitle>Courses — University Course Catalog</PageTitle>

<div class="container py-4">
    <h1 class="mb-4">Course Catalog</h1>

    <form method="get" action="/courses" class="row g-3 mb-4">
        <div class="col-md-6">
            <label for="search" class="form-label">Search</label>
            <input type="text" id="search" name="search" value="@Search" class="form-control" placeholder="Course title, code, or instructor…" />
        </div>
        <div class="col-md-4">
            <label for="department" class="form-label">Department</label>
            <select id="department" name="department" class="form-select">
                <option value="">All Departments</option>
                @foreach (var dept in Catalog.GetDepartments())
                {
                    <option value="@dept.Code" selected="@(dept.Code == Department)">@dept.Name</option>
                }
            </select>
        </div>
        <div class="col-md-2 d-flex align-items-end">
            <button type="submit" class="btn btn-primary w-100">Filter</button>
        </div>
    </form>

    @{
        var results = Catalog.SearchCourses(Search, Department);
    }

    @if (results.Count == 0)
    {
        <div class="alert alert-info">No courses match your search criteria.</div>
    }
    else
    {
        <p class="text-muted mb-3">Showing @results.Count course(s)</p>

        <div class="table-responsive">
            <table class="table table-striped table-hover">
                <thead class="table-dark">
                    <tr>
                        <th>Code</th>
                        <th>Title</th>
                        <th>Department</th>
                        <th>Credits</th>
                        <th>Instructor</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var course in results)
                    {
                        <tr>
                            <td>@course.Code</td>
                            <td>@course.Title</td>
                            <td>@course.DepartmentCode</td>
                            <td>@course.Credits</td>
                            <td>@course.InstructorName</td>
                            <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
</div>

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery]
    public string? Department { get; set; }
}

@page "/enroll"
@inject UniversityCourseCatalog.Services.CatalogService Catalog

<PageTitle>Enrollment Request — University Course Catalog</PageTitle>

<div class="container py-4" style="max-width: 600px;">
    <h1 class="mb-4">Enrollment Request</h1>

    @if (Submitted)
    {
        <div class="alert alert-success">
            <h4 class="alert-heading">Request Submitted!</h4>
            <p>Thank you, <strong>@Model.FullName</strong>. Your enrollment request for
                <strong>@(Catalog.GetCourse(Model.CourseId)?.Title ?? "the selected course")</strong>
                has been received. You will be notified by email once it is processed.</p>
            <hr />
            <a href="/courses" class="btn btn-outline-success">Browse More Courses</a>
        </div>
    }
    else
    {
        <EditForm method="post" Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment" Enhance>
            <DataAnnotationsValidator />
            <AntiforgeryToken />

            <div class="mb-3">
                <label for="fullName" class="form-label">Full Name</label>
                <InputText id="fullName" @bind-Value="Model.FullName" class="form-control" />
                <ValidationMessage For="() => Model.FullName" />
            </div>

            <div class="mb-3">
                <label for="studentId" class="form-label">Student ID</label>
                <InputText id="studentId" @bind-Value="Model.StudentId" class="form-control" />
                <ValidationMessage For="() => Model.StudentId" />
            </div>

            <div class="mb-3">
                <label for="courseId" class="form-label">Course</label>
                <InputSelect id="courseId" @bind-Value="Model.CourseId" class="form-select">
                    <option value="0">— Select a course —</option>
                    @foreach (var course in Catalog.GetAllCourses())
                    {
                        <option value="@course.Id">@course.Code — @course.Title</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.CourseId" />
            </div>

            <button type="submit" class="btn btn-success w-100">Submit Request</button>
        </EditForm>
    }
</div>

@code {
    [SupplyParameterFromForm]
    public UniversityCourseCatalog.Models.EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private bool Submitted { get; set; }

    protected override void OnInitialized()
    {
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        Submitted = true;
    }
}

